{{(() => {
  const selected = appsmith.store.botConfigSelected || {};
  const currentValue = selected.chatwoot_team_id ? String(selected.chatwoot_team_id) : "";
  const currentLabel = selected.chatwoot_team_id
    ? `${selected.chatwoot_team_name || selected.bot_name || "Time"} (#${selected.chatwoot_team_id})`
    : null;

  const currentOption = currentValue ? [{ label: currentLabel, value: currentValue }] : [];

  const dbOptions = (ListChatwootTeams.data || [])
    .map((r) => ({ label: String(r.label), value: String(r.value) }))
    .filter((o) => !currentValue || o.value !== currentValue);

  return currentOption.concat(dbOptions);
})()}}
